head.script:
scwin.count2 = 0;
scwin.count3 = 0;
scwin.clsCd = 0;
scwin.imptotal = 0;
scwin.exptotal = 0;

scwin.onpageload = async function() {
    $c.gus.cfDisableBtn([btn_save, btn_AddShift, btn_DeleteShift, btn_CancelShift, btn_Caculate]);

    dma_sellingItemCondition.set("sellItemCd1", "03");
    dma_sellingItemCondition.set("sellItemCd2", "0172");
    dma_sellingItemCondition.set("sellItemCd3", "0177");
    await $c.sbm.execute(sbm_sellingItemCondition);

    dma_conditionContract.set("cvsslMgntNo", "");
    dma_conditionContract.set("wrkStpCd", "");
    dma_conditionContract.set("odrKndCd", "");

    ed_cvsslMgntNo.setFocus();
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_RetrieveShiftingResults();
};

scwin.btn_PopUp_onclick = function(e) {
    scwin.f_openPopUp();
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.btn_save_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_Caculate_onclick = function(e) {
    scwin.f_Caculate();
};

scwin.btn_AddShift_onclick = function(e) {
    scwin.f_AddRowShift();
};

scwin.btn_DeleteShift_onclick = function(e) {
    scwin.f_DeleteRowShift();
};

scwin.btn_CancelShift_onclick = function(e) {
    ds_cargoShiftingResults.undoAll();
};

scwin.f_RetrieveShiftingResults = async function() {
    if (!(await $c.gus.cfValidate([ed_cvsslMgntNo]))) return;

    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());

    dma_caculateShiftingSelling.set("ctrtNo", "");
    dma_caculateShiftingSelling.set("selpchItemCd", "");
    dma_caculateShiftingSelling.set("crcCd", "");
    dma_caculateShiftingSelling.set("ctrtTrf", "");
    dma_caculateShiftingSelling.set("ctrtTrfFcrc", "");
    dma_caculateShiftingSelling.set("unitCd", "");
    dma_caculateShiftingSelling.set("unitClsCd", "");
    dma_caculateShiftingSelling.set("ctrtWrkPathSeq", "");
    dma_caculateShiftingSelling.set("unitNm", "");
    dma_caculateShiftingSelling.set("stdDt", "");

    await $c.sbm.execute(sbm_condition);

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        dma_caculateShiftingSelling.set("ctrtNo", "");
        dma_caculateShiftingSelling.set("selpchItemCd", "");
        dma_caculateShiftingSelling.set("crcCd", ds_cargoShiftingResults.getCellData(i, "crcCd"));
        dma_caculateShiftingSelling.set("ctrtTrf", "");
        dma_caculateShiftingSelling.set("ctrtTrfFcrc", "");
        dma_caculateShiftingSelling.set("unitCd", "");
        dma_caculateShiftingSelling.set("unitClsCd", "");
        dma_caculateShiftingSelling.set("ctrtWrkPathSeq", "");
        dma_caculateShiftingSelling.set("unitNm", "");
        dma_caculateShiftingSelling.set("stdDt", ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));

        await $c.sbm.execute(sbm_ExchRate);

        ds_cargoShiftingResults.setCellData(i, "stdExchRt", ds_ExchRate.getCellData(0, "stdExchRt"));
    }
};

scwin.f_DivHoldEachWorkPlanList = function() {
    let vsslNm = "";
    let lineNm = "";
    let shpCoNm = "";
    let impPortcnt = "";
    let expPortcnt = "";
    let impRepKcg = "";
    let expRepKcg = "";
    let wrkPlNm = "";
    let arrvlportDtm = "";
    let deprtportDtm = "";
    let cfmanNm = "";
    let cvsslFmanCnt = "";
    let groundFmanCnt = "";

    if (ds_carryingVesselBasisInfo.getRowCount() > 0) {
        vsslNm = ds_carryingVesselBasisInfo.getCellData(0, "vsslNm");
        lineNm = ds_carryingVesselBasisInfo.getCellData(0, "lineNm");
        shpCoNm = ds_carryingVesselBasisInfo.getCellData(0, "shpCoNm");
        impPortcnt = ds_carryingVesselBasisInfo.getCellData(0, "impPortcnt");
        expPortcnt = ds_carryingVesselBasisInfo.getCellData(0, "expPortcnt");
        impRepKcg = ds_carryingVesselBasisInfo.getCellData(0, "impRepKcg");
        expRepKcg = ds_carryingVesselBasisInfo.getCellData(0, "expRepKcg");
        wrkPlNm = ds_carryingVesselBasisInfo.getCellData(0, "wrkPlNm");
        if (ds_carryingVesselBasisInfo.getCellData(0, "arrvlportDtm") == "") {
            arrvlportDtm = "";
        } else {
            arrvlportDtm = $c.gus.cfGetFormatStr(ds_carryingVesselBasisInfo.getCellData(0, "arrvlportDtm"), "####/##/## ##:##");
        }
        if (ds_carryingVesselBasisInfo.getCellData(0, "deprtportDtm") == "") {
            deprtportDtm = "";
        } else {
            deprtportDtm = $c.gus.cfGetFormatStr(ds_carryingVesselBasisInfo.getCellData(0, "deprtportDtm"), "####/##/## ##:##");
        }
        cfmanNm = ds_carryingVesselBasisInfo.getCellData(0, "cfmanNm");
        cvsslFmanCnt = ds_carryingVesselBasisInfo.getCellData(0, "cvsslFmanCnt");
        groundFmanCnt = ds_carryingVesselBasisInfo.getCellData(0, "groundFmanCnt");
    }

    let carryingVesselBasisInfo = "";
    carryingVesselBasisInfo = carryingVesselBasisInfo +
        '\x3Ctable class="table_bg" cellpadding="2" cellspacing="1" border="0" width="100%">' +
        '	\x3Ctr>' +
        '		\x3Ctd width="12%" class="table_header_right">선명\x3C/td>' +
        '		\x3Ctd width="20%" class="table_bg_bright">' + vsslNm + '\x3C/td>' +
        '		\x3Ctd width="12%" class="table_header_right">LINE\x3C/td>' +
        '		\x3Ctd width="24%" class="table_bg_bright">' + lineNm + '\x3C/td>' +
        '		\x3Ctd width="12%" class="table_header_right">선사\x3C/td>' +
        '		\x3Ctd width="20%" class="table_bg_bright">' + shpCoNm + '\x3C/td>' +
        '	\x3C/tr>';
    if (ds_carryingVesselBasisInfo.getRowCount() == 0) {
        carryingVesselBasisInfo = carryingVesselBasisInfo +
            '	\x3Ctr>' +
            '		\x3Ctd width="12%" class="table_header_right">항차\x3C/td>' +
            '		\x3Ctd width="20%" class="table_bg_bright">&nbsp;\x3C/td>' +
            '		\x3Ctd width="12%" class="table_header_right">대표화종\x3C/td>' +
            '		\x3Ctd width="24%" class="table_bg_bright">&nbsp;\x3C/td>' +
            '		\x3Ctd width="12%" class="table_header_right">수출입구분\x3C/td>' +
            '		\x3Ctd width="20%" class="table_bg_bright">&nbsp;\x3C/td>' +
            '	\x3C/tr>';
    } else {
        let curRow = ds_carryingVesselBasisInfo.getRowPosition();
        if (ds_carryingVesselBasisInfo.getCellData(curRow, "impportcnt") != "") {
            carryingVesselBasisInfo = carryingVesselBasisInfo +
                '	\x3Ctr>' +
                '		\x3Ctd width="12%" class="table_header_right">항차\x3C/td>' +
                '		\x3Ctd width="20%" class="table_bg_bright">' + impPortcnt + '\x3C/td>' +
                '		\x3Ctd width="12%" class="table_header_right">대표화종\x3C/td>' +
                '		\x3Ctd width="24%" class="table_bg_bright">' + impRepKcg + '\x3C/td>' +
                '		\x3Ctd width="12%" class="table_header_right">수출입구분\x3C/td>' +
                '		\x3Ctd width="20%" class="table_bg_bright">수입\x3C/td>' +
                '	\x3C/tr>';
        }
        if (ds_carryingVesselBasisInfo.getCellData(curRow, "expportcnt") != "") {
            carryingVesselBasisInfo = carryingVesselBasisInfo +
                '	\x3Ctr>' +
                '		\x3Ctd width="12%" class="table_header_right">항차\x3C/td>' +
                '		\x3Ctd width="20%" class="table_bg_bright">' + expPortcnt + '\x3C/td>' +
                '		\x3Ctd width="12%" class="table_header_right">대표화종\x3C/td>' +
                '		\x3Ctd width="24%" class="table_bg_bright">' + expRepKcg + '\x3C/td>' +
                '		\x3Ctd width="12%" class="table_header_right">수출입구분\x3C/td>' +
                '		\x3Ctd width="20%" class="table_bg_bright">수출\x3C/td>' +
                '	\x3C/tr>';
        }
    }
    carryingVesselBasisInfo = carryingVesselBasisInfo +
        '	\x3Ctr>' +
        '		\x3Ctd width="12%" class="table_header_right">작업장\x3C/td>' +
        '		\x3Ctd width="20%" class="table_bg_bright">' + wrkPlNm + '\x3C/td>' +
        '		\x3Ctd width="12%" class="table_header_right">입항(예정)일시\x3C/td>' +
        '		\x3Ctd width="24%" class="table_bg_bright">' + arrvlportDtm + '\x3C/td>' +
        '		\x3Ctd width="12%" class="table_header_right">출항(예정)일시\x3C/td>' +
        '		\x3Ctd width="20%" class="table_bg_bright">' + deprtportDtm + '\x3C/td>' +
        '	\x3C/tr>' +
        '	\x3Ctr>' +
        '		\x3Ctd width="12%" class="table_header_right">Chief 포맨\x3C/td>' +
        '		\x3Ctd width="20%" class="table_bg_bright">' + cfmanNm + '\x3C/td>' +
        '		\x3Ctd width="12%" class="table_header_right">본선포맨\x3C/td>' +
        '		\x3Ctd width="24%" class="table_bg_bright">' + cvsslFmanCnt + '\x3C/td>' +
        '		\x3Ctd width="12%" class="table_header_right">육상포맨\x3C/td>' +
        '		\x3Ctd width="20%" class="table_bg_bright">' + groundFmanCnt + '\x3C/td>' +
        '	\x3C/tr>' +
        '\x3C/table>';

    // TODO: div_carryingVesselBasisInfo.innerHTML 동적 HTML 삽입 — WebSquare에서 별도 처리 필요
};

scwin.f_CarryingVesselCompletionInformation = function() {
    let impExpClsNm = "";
    let cvsslWrkCompleteYn = "";
    let cvsslWrkCompleteDt = "";

    let html = "";
    if (ds_carryingVesselCompletionInformation.getRowCount() > 0) {
        html = html +
            '\x3Ctable class="table_bg" cellpadding="2" cellspacing="1" border="0" width="100%">';
        for (let i = 0; i < ds_carryingVesselCompletionInformation.getRowCount(); i++) {
            impExpClsNm = ds_carryingVesselCompletionInformation.getCellData(i, "impExpClsNm");
            cvsslWrkCompleteYn = ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteYn");

            if (ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt") != "") {
                cvsslWrkCompleteDt = $c.gus.cfGetFormatStr(ds_carryingVesselCompletionInformation.getCellData(i, "cvsslWrkCompleteDt"), "####/##/##");
            } else {
                cvsslWrkCompleteDt = "";
            }

            if (cvsslWrkCompleteYn == "1") {
                cvsslWrkCompleteYn = "Yes";
            } else {
                cvsslWrkCompleteYn = "No";
            }

            html = html +
                '	\x3Ctr>' +
                '		\x3Ctd width="12%" class="table_header_right">수출입구분\x3C/td>' +
                '		\x3Ctd width="20%" class="table_bg_bright">' + impExpClsNm + '\x3C/td>' +
                '		\x3Ctd width="12%" class="table_header_right">본선완료여부\x3C/td>' +
                '		\x3Ctd width="24%" class="table_bg_bright">' + cvsslWrkCompleteYn + '\x3C/td>' +
                '		\x3Ctd width="12%" class="table_header_right">본선완료일자\x3C/td>' +
                '		\x3Ctd width="20%" class="table_bg_bright">' + cvsslWrkCompleteDt + '\x3C/td>' +
                '	\x3C/tr>';
        }
        html = html + '\x3C/table>';
    } else {
        html = html +
            '\x3Ctable class="table_bg" cellpadding="2" cellspacing="1" border="0" width="100%">' +
            '	\x3Ctr>' +
            '		\x3Ctd width="12%" class="table_header_right">수출입구분\x3C/td>' +
            '		\x3Ctd width="20%" class="table_bg_bright">' + impExpClsNm + '\x3C/td>' +
            '		\x3Ctd width="12%" class="table_header_right">본선완료여부\x3C/td>' +
            '		\x3Ctd width="24%" class="table_bg_bright">' + cvsslWrkCompleteYn + '\x3C/td>' +
            '		\x3Ctd width="12%" class="table_header_right">본선완료일자\x3C/td>' +
            '		\x3Ctd width="20%" class="table_bg_bright">' + cvsslWrkCompleteDt + '\x3C/td>' +
            '	\x3C/tr>' +
            '\x3C/table>';
    }
    // TODO: div_CarryingVesselCompletionInformation.innerHTML 동적 HTML 삽입 — WebSquare에서 별도 처리 필요
};

scwin.f_FieldClear = function() {
    ed_cvsslMgntNo.setValue("");
    ed_cvsslMgntNo.setFocus();
};

scwin.f_shiftingExcel = function() {
    $c.data.downloadGridViewExcel(gr_cargoShiftingResults, {fileName: "Shifting매출.xlsx", sheetName: "Shifting매출"});
};

scwin.f_AddRowShift = function() {
    ds_cargoShiftingResults.insertRow(ds_cargoShiftingResults.getRowCount());
    let curRow = ds_cargoShiftingResults.getRowCount() - 1;
    let prevRow = curRow - 1;
    if (prevRow >= 0) {
        ds_cargoShiftingResults.setCellData(curRow, "odrNo", ds_cargoShiftingResults.getCellData(prevRow, "odrNo"));
        ds_cargoShiftingResults.setCellData(curRow, "cvsslMgntNo", ds_cargoShiftingResults.getCellData(prevRow, "cvsslMgntNo"));
        ds_cargoShiftingResults.setCellData(curRow, "impExpClsNm", ds_cargoShiftingResults.getCellData(prevRow, "impExpClsNm"));
        ds_cargoShiftingResults.setCellData(curRow, "impExpClsCd", ds_cargoShiftingResults.getCellData(prevRow, "impExpClsCd"));
        ds_cargoShiftingResults.setCellData(curRow, "selpchItemNm", ds_cargoShiftingResults.getCellData(prevRow, "selpchItemNm"));
        ds_cargoShiftingResults.setCellData(curRow, "selpchItemCd", ds_cargoShiftingResults.getCellData(prevRow, "selpchItemCd"));
        ds_cargoShiftingResults.setCellData(curRow, "commNm", ds_cargoShiftingResults.getCellData(prevRow, "commNm"));
        ds_cargoShiftingResults.setCellData(curRow, "commCd", ds_cargoShiftingResults.getCellData(prevRow, "commCd"));
        ds_cargoShiftingResults.setCellData(curRow, "wrkStpNm", ds_cargoShiftingResults.getCellData(prevRow, "wrkStpNm"));
        ds_cargoShiftingResults.setCellData(curRow, "wrkStpCd", ds_cargoShiftingResults.getCellData(prevRow, "wrkStpCd"));
        ds_cargoShiftingResults.setCellData(curRow, "cntrSizCd", ds_cargoShiftingResults.getCellData(prevRow, "cntrSizCd"));
        ds_cargoShiftingResults.setCellData(curRow, "ctrtNo", ds_cargoShiftingResults.getCellData(prevRow, "ctrtNo"));
        ds_cargoShiftingResults.setCellData(curRow, "berthCd", ds_cargoShiftingResults.getCellData(prevRow, "berthCd"));
    }
    ds_cargoShiftingResults.setCellData(curRow, "sellClsCd", "N");
};

scwin.f_DeleteRowShift = function() {
    let curRow = ds_cargoShiftingResults.getRowPosition();
    if (curRow < 0) return;
    if (ds_cargoShiftingResults.getCellData(curRow, "cargoShiftingRsltsSeq") == 0) {
        ds_cargoShiftingResults.removeRow(curRow);
    } else {
        ds_cargoShiftingResults.deleteRow(curRow);
    }
};

scwin.f_Round = async function(Num, Position, Base) {
    if (Position == 0) {
        return Math.round(Num);
    } else if (Position > 0) {
        let cipher = '1';
        for (let i = 0; i < Position; i++)
            cipher = cipher + '0';

        let no = Number(cipher);

        if (Base == "F") {
            return Math.round(Num * no) / no;
        } else {
            return Math.round(Num / no) * no;
        }
    } else {
        await $c.win.alert("자릿수는 정수로만 구분합니다.");
        return false;
    }
};

scwin.f_Save = async function() {
    let count = 0;
    let count1 = 0;
    let chg = 0;
    let hodrNo = "";
    let delcount = 0;

    for (let i = 0; i < ds_caculateShiftingSellingHidden1.getRowCount(); i++) {
        for (let j = 0; j < ds_cargoShiftingResults.getRowCount(); j++) {
            if (ds_cargoShiftingResults.getCellData(j, "chk") == "T") {
                if (ds_cargoShiftingResults.getCellData(j, "adptQty") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptQty")
                    || ds_cargoShiftingResults.getCellData(j, "adptWt") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptWt")
                    || ds_cargoShiftingResults.getCellData(j, "adptCbm") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptCbm")
                    || ds_cargoShiftingResults.getCellData(j, "sellAmtFcrc") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellAmtFcrc")
                    || ds_cargoShiftingResults.getCellData(j, "sellAmt") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellAmt")
                    || ds_cargoShiftingResults.getCellData(j, "sellCtrlAmtFcrc") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellCtrlAmtFcrc")) {
                    ds_cargoShiftingResults.setCellData(j, "commNm", ds_caculateShiftingSellingHidden1.getCellData(i, "commNm") + " ");
                    chg++;
                }
            }
        }
    }

    if (!(await $c.gus.cfValidate([gr_cargoShiftingResults]))) {
        return;
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getCellData(i, "selpchItemCd") == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["매출항목"]);
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T") {
            count++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getRowStatus(i) == "D") {
            count1++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getRowStatus(i) == "C" && scwin.count2 == 0) {
            scwin.count3++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T") {
            if (ds_cargoShiftingResults.getCellData(i, "ctrtTrf") == 0) {
                await $c.gus.cfAlertMsg((i + 1) + "번째 데이터의 계약요율이 존재하지 않으므로 " + (i + 1) + "번째 데이터는 저장할수가 없습니다.");
                ds_cargoShiftingResults.setCellData(i, "chk", "F");
                scwin.count3 = 0;
                scwin.count2++;
                return false;
            }
        }
    }

    if (chg == 0 && scwin.count3 == 0 && count1 == 0) {
        for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
            if (ds_cargoShiftingResults.getCellData(i, "chk") == "F") {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["수정할 데이터의 체크박스"]);
                return false;
            } else {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["SHIFTING 매출"]);
                return false;
            }
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getCellData(i, "sellClsCd") == "N") {
            ds_cargoShiftingResults.setRowStatus(i, "C");
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T"
            && ds_cargoShiftingResults.getCellData(i, "adptQty") == 0 && ds_cargoShiftingResults.getCellData(i, "adptWt") == 0
            && ds_cargoShiftingResults.getCellData(i, "adptCbm") == 0
            && ds_cargoShiftingResults.getCellData(i, "sellCtrlAmtFcrc") == 0) {
            await $c.win.alert((i + 1) + "번째 데이터는 변경된 사항이 없습니다. 선택된 체크박스를 해제해 주십시오.");
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getRowStatus(i) == "D") {
            delcount = delcount + 1;
        }
    }

    if (count == 0 && count1 == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["수정할 데이터의 체크박스"]);
        return false;
    } else {
        if (delcount != ds_cargoShiftingResults.getRowCount()) {
            let chk = await $c.win.confirm("선택된 데이터만 저장이 가능합니다.저장하시겠습니까?");
            if (chk) {
                await $c.sbm.execute(sbm_save);
            }
        } else {
            let chk = await $c.win.confirm("저장하시겠습니까?");
            if (chk) {
                await $c.sbm.execute(sbm_save);
            }
        }
    }
};

scwin.f_Caculate = async function() {
    let count = 0;
    if (!(await $c.gus.cfValidate([ed_cvsslMgntNo]))) {
        return;
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getCellData(i, "selpchItemCd") == "") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["매출항목"]);
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T") {
            count++;
            break;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (count == 0 && ds_cargoShiftingResults.getRowStatus(i) == "D") {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["행삭제를 한 데이터", "SHIFTING 매출 계산을"]);
            return false;
        }
    }

    if (count == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["SHIFTING 매출을 계산할 매출항목"]);
        return false;
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getCellData(i, "adptQty") == 0
            && ds_cargoShiftingResults.getCellData(i, "adptWt") == 0 && ds_cargoShiftingResults.getCellData(i, "adptCbm") == 0) {
            await $c.gus.cfAlertMsg("수량 혹은 중량 중 하나는 0보다 큰 값으로 입력하십시오.");
            return false;
        }
    }

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T") {
            ds_cargoShiftingResults.setCellData(i, "commNm", ds_cargoShiftingResults.getCellData(i, "commNm") + " ");
        }
    }

    ds_caculateShiftingSellingHidden.removeAll();
    ds_caculateShiftingSellingHidden2.removeAll();

    dma_caculateShiftingSelling.set("ctrtNo", "");
    dma_caculateShiftingSelling.set("selpchItemCd", "");
    dma_caculateShiftingSelling.set("crcCd", "");
    dma_caculateShiftingSelling.set("ctrtTrf", "");
    dma_caculateShiftingSelling.set("ctrtTrfFcrc", "");
    dma_caculateShiftingSelling.set("unitCd", "");
    dma_caculateShiftingSelling.set("unitClsCd", "");
    dma_caculateShiftingSelling.set("ctrtWrkPathSeq", "");
    dma_caculateShiftingSelling.set("unitNm", "");
    dma_caculateShiftingSelling.set("stdDt", "");

    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
        if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getRowStatus(i) != "D") {
            ds_caculateShiftingSellingHidden2.removeAll();
            let newIdx = ds_caculateShiftingSellingHidden2.insertRow(0);
            let colList = ["chk","cargoShiftingRsltsSeq","cvsslMgntNo","impExpClsCd","impExpClsNm","selpchItemCd","selpchItemNm","sellClsCd","commCd","commNm","wrkStpCd","wrkStpNm","rsltsQty","rsltsWt","rsltsCbm","adptQty","adptWt","adptCbm","ctrtTrf","crcCd","unitCd","unitNm","ctrtNo","ctrtNoDetail","ctrtWrkPathSeq","ctrtWrkStpSeq","taxnClsCd","sellAmtFcrc","sellAmt","sellCtrlAmtFcrc","sellCtrlAmt","odrNo","odrKndCd","sellSeq","stdExchRt","cntrSizCd","cntrTypCd","fullEmptyClsCd","berthCd","unitClsCd","impTotal","expTotal"];
            for (let c = 0; c < colList.length; c++) {
                ds_caculateShiftingSellingHidden2.setCellData(0, colList[c], ds_cargoShiftingResults.getCellData(i, colList[c]));
            }
            await $c.sbm.execute(sbm_caculate);
            await scwin.f_Caculate1(i);
        }
    }
};

scwin.f_Caculate1 = async function(row) {
    if (dma_caculateShiftingSelling.get("crcCd") == "" && dma_caculateShiftingSelling.get("ctrtNo") == "") {
        await $c.gus.cfAlertMsg((row + 1) + "번째 데이터의 계약요율이 없습니다.");
        return false;
    }

    if (dma_caculateShiftingSelling.get("crcCd") == "") {
        await $c.gus.cfAlertMsg((row + 1) + "번째 데이터의 계약요율이 없습니다.");
        return false;
    }

    dma_caculateShiftingSelling_1.set("ctrtNo", dma_caculateShiftingSelling.get("ctrtNo"));
    dma_caculateShiftingSelling_1.set("selpchItemCd", dma_caculateShiftingSelling.get("selpchItemCd"));
    dma_caculateShiftingSelling_1.set("crcCd", dma_caculateShiftingSelling.get("crcCd"));
    dma_caculateShiftingSelling_1.set("ctrtTrf", dma_caculateShiftingSelling.get("ctrtTrf"));
    dma_caculateShiftingSelling_1.set("ctrtTrfFcrc", dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
    dma_caculateShiftingSelling_1.set("unitCd", dma_caculateShiftingSelling.get("unitCd"));
    dma_caculateShiftingSelling_1.set("unitClsCd", dma_caculateShiftingSelling.get("unitClsCd"));
    dma_caculateShiftingSelling_1.set("ctrtWrkPathSeq", dma_caculateShiftingSelling.get("ctrtWrkPathSeq"));
    dma_caculateShiftingSelling_1.set("unitNm", dma_caculateShiftingSelling.get("unitNm"));
    dma_caculateShiftingSelling_1.set("stdDt", dma_caculateShiftingSelling.get("stdDt"));

    dma_caculateShiftingSelling.set("ctrtNo", dma_caculateShiftingSelling_1.get("ctrtNo"));
    dma_caculateShiftingSelling.set("selpchItemCd", dma_caculateShiftingSelling_1.get("selpchItemCd"));
    dma_caculateShiftingSelling.set("crcCd", dma_caculateShiftingSelling_1.get("crcCd"));
    dma_caculateShiftingSelling.set("ctrtTrf", dma_caculateShiftingSelling_1.get("ctrtTrf"));
    dma_caculateShiftingSelling.set("ctrtTrfFcrc", dma_caculateShiftingSelling_1.get("ctrtTrfFcrc"));
    dma_caculateShiftingSelling.set("unitCd", dma_caculateShiftingSelling_1.get("unitCd"));
    dma_caculateShiftingSelling.set("unitClsCd", dma_caculateShiftingSelling_1.get("unitClsCd"));
    dma_caculateShiftingSelling.set("ctrtWrkPathSeq", dma_caculateShiftingSelling_1.get("ctrtWrkPathSeq"));
    dma_caculateShiftingSelling.set("unitNm", dma_caculateShiftingSelling_1.get("unitNm"));
    dma_caculateShiftingSelling.set("stdDt", ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));

    await $c.sbm.execute(sbm_ExchRate);

    ds_cargoShiftingResults.setCellData(row, "stdExchRt", ds_ExchRate.getCellData(0, "stdExchRt"));

    if (dma_caculateShiftingSelling.get("crcCd") == "KRW") {
        if (dma_caculateShiftingSelling.get("unitClsCd") == "01") {
            ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptQty") * dma_caculateShiftingSelling.get("ctrtTrf"));
        } else if (dma_caculateShiftingSelling.get("unitClsCd") == "02") {
            if (dma_caculateShiftingSelling.get("unitCd") == "KG") {
                ds_cargoShiftingResults.setCellData(row, "sellAmt", (ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrf")) * 1000);
            } else {
                ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrf"));
            }
        } else if (dma_caculateShiftingSelling.get("unitClsCd") == "04") {
            if (dma_caculateShiftingSelling.get("unitCd") == "R/T") {
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > ds_cargoShiftingResults.getCellData(row, "adptCbm")) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrf"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptCbm") * dma_caculateShiftingSelling.get("ctrtTrf"));
                }
            } else if (dma_caculateShiftingSelling.get("unitCd") == "RNT") {
                let v_Cbm = scwin.f_Round((ds_cargoShiftingResults.getCellData(row, "adptCbm") / 1.133), 3, 'F');
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > v_Cbm) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrf"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", v_Cbm * dma_caculateShiftingSelling.get("ctrtTrf"));
                }
            }
        }
        ds_cargoShiftingResults.setCellData(row, "ctrtTrf", dma_caculateShiftingSelling.get("ctrtTrf"));
        ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", 0);
        ds_cargoShiftingResults.setCellData(row, "sellCtrlAmtFcrc", 0);
    } else {
        if (dma_caculateShiftingSelling.get("unitClsCd") == "01") {
            ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptQty") * dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
            ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
        } else if (dma_caculateShiftingSelling.get("unitClsCd") == "02") {
            if (dma_caculateShiftingSelling.get("unitCd") == "KG") {
                ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrfFcrc") * 1000);
                ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt") * 1000);
            } else {
                ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
                ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
            }
        } else if (dma_caculateShiftingSelling.get("unitClsCd") == "04") {
            if (dma_caculateShiftingSelling.get("unitCd") == "R/T") {
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > ds_cargoShiftingResults.getCellData(row, "adptCbm")) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptCbm") * dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                }
            } else if (dma_caculateShiftingSelling.get("unitCd") == "RNT") {
                let v_Cbm = scwin.f_Round((ds_cargoShiftingResults.getCellData(row, "adptCbm") / 1.133), 3, 'F');
                if (ds_cargoShiftingResults.getCellData(row, "adptWt") > v_Cbm) {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", ds_cargoShiftingResults.getCellData(row, "adptWt") * dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                } else {
                    ds_cargoShiftingResults.setCellData(row, "sellAmtFcrc", v_Cbm * dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
                    ds_cargoShiftingResults.setCellData(row, "sellAmt", ds_cargoShiftingResults.getCellData(row, "sellAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
                }
            }
        }

        if (ds_cargoShiftingResults.getCellData(row, "sellCtrlAmtFcrc") > 0) {
            ds_cargoShiftingResults.setCellData(row, "sellCtrlAmt", ds_cargoShiftingResults.getCellData(row, "sellCtrlAmtFcrc") * ds_cargoShiftingResults.getCellData(row, "stdExchRt"));
        } else if (ds_cargoShiftingResults.getCellData(row, "sellCtrlAmtFcrc") == 0) {
            ds_cargoShiftingResults.setCellData(row, "sellCtrlAmt", 0);
        }
        ds_cargoShiftingResults.setCellData(row, "ctrtTrf", dma_caculateShiftingSelling.get("ctrtTrfFcrc"));
    }

    ds_cargoShiftingResults.setCellData(row, "crcCd", dma_caculateShiftingSelling.get("crcCd"));
    ds_cargoShiftingResults.setCellData(row, "unitCd", dma_caculateShiftingSelling.get("unitCd"));
    ds_cargoShiftingResults.setCellData(row, "unitNm", dma_caculateShiftingSelling.get("unitNm"));
    ds_cargoShiftingResults.setCellData(row, "ctrtNo", dma_caculateShiftingSelling.get("ctrtNo"));
    ds_cargoShiftingResults.setCellData(row, "unitClsCd", dma_caculateShiftingSelling.get("unitClsCd"));

    ds_cargoShiftingResults.setCellData(row, "commNm", ds_cargoShiftingResults.getCellData(row, "commNm") + " ");

    if (ds_cargoShiftingResults.getCellData(row, "crcCd") == "KRW") {
        gr_cargoShiftingResults.setColumnProp("sellCtrlAmtFcrc", "readOnly", true);
        gr_cargoShiftingResults.setColumnProp("sellCtrlAmt", "readOnly", false);
    } else {
        gr_cargoShiftingResults.setColumnProp("sellCtrlAmtFcrc", "readOnly", false);
        gr_cargoShiftingResults.setColumnProp("sellCtrlAmt", "readOnly", true);
    }
};

